import {Component,OnInit, ViewChild,ElementRef,Inject} from '@angular/core';
import {HttpClient} from '@angular/common/http';
import { MAT_DIALOG_DATA,MatDialogRef } from '@angular/material/dialog';


@Component({
    selector: 'app-imageoneshot-modal',
    templateUrl: './imageoneshot-modal.component.html',
    styleUrls: ['./imageoneshot-modal.component.css']
})

export class ImageOneShotModalComponent implements OnInit  {
    constructor( @Inject( MAT_DIALOG_DATA ) public data: any ,public dialogRef:MatDialogRef<ImageOneShotModalComponent>,private httpclient: HttpClient) { }
    // applicationName:string;
    // subapplicationName:string;
    // errorName:string;
    // resolutionStep:string;
    columnsSelected:any=[];
    columnNames:any=[];

    ngOnInit(){

        alert("inisde ngonit");

        this.httpclient.get('/api/imageAnalysis/getColumnNames').subscribe(data=> {
            if(data['response'] != 'failure'){
                this.columnsSelected=data ['response'];
              console.log("columnsSelected is ",this.columnsSelected);
              this.columnNames=this.columnsSelected
              console.log("columns are ",this.columnNames);
            }else{
              console.warn('Could not get data from api!');
            }
          }, err=> {
            console.error('Could not get data! ,'+err)
          });

          for(let i=0;i<this.columnNames.length;i++){
            this.data_to_send[this.columnNames[i]]='';
          }


    }

    data_to_send={};
    // img_url:string;
    img_name:string;
    // app_name:string;
    // sub_appname:string;
    error_details:string;
    // resolution_steps:string;
    image_trained_state:boolean=false;

    uploadImage_and_Train(){
        // this.urls.push({'url':event.target.result,'image_name':'','app_name':'','sub_appname':'', 'error_details':'','resolution_steps':''}); 
        // this.data_to_send['image_url']=this.data.img_url;
        this.data_to_send['incident_number']=this.data.incident_no;
        this.data_to_send['image_name']=this.img_name;
        // this.data_to_send['app_name']=this.app_name;
        // this.data_to_send['sub_appname']=this.sub_appname;
        this.data_to_send['error_details']=this.error_details;
        // this.data_to_send['resolution_steps']=this.resolution_steps;
        // alert();
        // for(let i=0;i<this.columnNames.length;i++){
        //     this.data_to_send[this.columnNames[i]]=this.data_to_send[this.columnNames[i]];
        //   }

        console.log("data to send ",this.data_to_send)

        this.httpclient.post('/api/newimage/savevector', this.data_to_send, {responseType: 'text'})
            .subscribe(data => {
              if(data == "success") {
                    this.image_trained_state=true;
                    this.dialogRef.close(this.image_trained_state);
              }else{
                console.log('Oops!!, No any data received');
                alert('Some issue occured while training this image  ,please check again ')
                this.dialogRef.close(this.image_trained_state);
                // this.image_trained_state=false;
               
              }
            });

        //have to call a post call with image and Data to sent to back end together in a single call 
        // if not try the same two post calls earlier we used in choose imagemodel compoenet
    }
    
    onNoClick():void{
        this.dialogRef.close();
        // this.data['app_name']='';
        // this.data['sub_appname']='';
        // this.data['error_name']='';
        // this.data['resol_step']='';
        
    }

}